const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();
const port = 3000;

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const twilioClient = twilio(accountSid, authToken);
const twilioPhoneNumber = 'your_twilio_phone_number';

// Middleware setup
app.use(bodyParser.json());
app.use(session({
  secret: 'your_session_secret',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: true, httpOnly: true }
}));

// Generate a secure random 6-digit code
function generateCode() {
  return crypto.randomInt(100000, 999999).toString();
}

// Send SMS using Twilio
function sendSMS(to, code) {
  return twilioClient.messages.create({
    body: `Your verification code is: ${code}`,
    from: twilioPhoneNumber,
    to: to
  });
}

// Route to request a verification code
app.post('/request-code', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  if (!phoneNumber || !/^\+\d{10,15}$/.test(phoneNumber)) {
    return res.status(400).send('Invalid phone number');
  }

  const code = generateCode();
  req.session.verificationCode = code;

  sendSMS(phoneNumber, code)
    .then(() => res.status(200).send('Verification code sent'))
    .catch(err => res.status(500).send('Failed to send SMS'));
});

// Route to verify the code
app.post('/verify-code', (req, res) => {
  const userCode = req.body.code;
  if (!userCode || !/^\d{6}$/.test(userCode)) {
    return res.status(400).send('Invalid code format');
  }

  if (req.session.verificationCode === userCode) {
    req.session.verificationCode = null; // Clear the code after successful verification
    return res.status(200).send('Verification successful');
  } else {
    return res.status(401).send('Invalid verification code');
  }
});

app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});